// NODO: Build_Stakeholder_Draft
// VERSIONE: 2.4 - Sincronizzazione simmetrica esclusiva di chat_id

const item = $input.first().json;
const wh = item.webhookUrl || "";

// 1. ESTRAZIONE E VALIDAZIONE REALE DEI DATI
const userData = item.body.user || {};
const billingArray = item.body.fatturazione || [];

// Estrazione sicura del chat_id in ingresso
const chat_id = userData.chat_id || (item.body.user ? item.body.user.chat_id : null);

// Supporto flessibile per vat_number o pIva in ingresso
const firstBilling = billingArray[0] || {};
const hasValidBilling = !!(billingArray.length > 0 && (firstBilling.vat_number || firstBilling.pIva || firstBilling.ragioneSociale));

// Mappatura verso il database con replica del chat_id
const billingData = hasValidBilling ? {
    ragioneSociale: firstBilling.ragioneSociale || null,
    vat_number: firstBilling.vat_number || firstBilling.pIva || null,
    codiceFiscale: firstBilling.codiceFiscale || null,
    indirizzo: firstBilling.indirizzo || null,
    comune: firstBilling.comune || null,
    provincia: firstBilling.provincia || null,
    cap: firstBilling.cap || null,
    sdi: firstBilling.sdi || null,
    pec: firstBilling.pec || null,
    chat_id: chat_id || firstBilling.chat_id || null // Replica chat_id se disponibile
} : null;

// Template vuoto con chat_id popolato per coerenza
const emptyBilling = {
    ragioneSociale: null,
    vat_number: null,
    codiceFiscale: null,
    indirizzo: null,
    comune: null,
    provincia: null,
    cap: null,
    sdi: null,
    pec: null,
    chat_id: chat_id || null // Preserva il chat_id anche senza fatturazione
};

// 2. DETERMINAZIONE ID ISTANZA
let instanceId = "GUEST";
if (hasValidBilling && billingData.vat_number) {
    instanceId = billingData.vat_number.replace('IT', '');
} else if (userData.codiceFiscale) {
    instanceId = userData.codiceFiscale;
} else if (userData.email) {
    instanceId = userData.email.replace(/[@.]/g, '_');
}

const timestampWelcome = new Date().toISOString();

// 3. COSTRUZIONE DOCUMENTO STAKEHOLDER
const stakeholderDraft = {
  document_type: "STAKEHOLDER_PROFILE",
  version: "2.4",
  owner_instance_id: instanceId,

  // ━━━ OWNER DATA REF (Sincronizzato) ━━━
  owner_data_ref: hasValidBilling ? { ...billingData } : emptyBilling,

  // ━━━ USER REF (Sincronizzato) ━━━
  user_ref: { 
    ...userData,
    chat_id: chat_id || null // Garantisce la presenza del chat_id in user_ref
  },

  metadata: {
    status: hasValidBilling ? "ACTIVE" : "PENDING_BILLING",
    created_at: timestampWelcome,
    last_updated: timestampWelcome,
    stakeholder_type: "USER"
  },

  professional_profile: {
    soft_skills_modules: {
      modulo1: { completed: false, date: null, time: null, results: null, timestamp: null },
      modulo2: { completed: false, date: null, time: null, results: null, timestamp: null },
      modulo3: { completed: false, date: null, time: null, results: null, timestamp: null },
      modulo4: { completed: false, date: null, time: null, results: null, timestamp: null }
    }
  },

  commercial_profile: {
    customer_since: timestampWelcome,
    tags: hasValidBilling ? ["primary_contact", "owner"] : ["incomplete_profile"],

    credit_balance: {
      available_credits: hasValidBilling ? 600 : 0,
      last_transaction_id: hasValidBilling ? "Pioneer_Welcome" : null,
      lifetime_value: 0,
      last_update: timestampWelcome
    }
  },

  booking_summary: {
    total_bookings: 0,
    active_booking_count: 0,
    historical_booking_ids: []
  }
};

// 4. GENERAZIONE CONDIZIONALE DEL TRANSACTION SUMMARY
const welcomeTransaction = hasValidBilling ? {
    id: "Pioneer_Welcome",
    action: "add",
    amount: 600,
    previous_balance: 0,
    final_balance: 600,
    timestamp: timestampWelcome,
    billing_source: {
        use: "Pioneer Welcome Gift",
        wh: wh
    }
} : null;

return [{
    json: {
        ...item,
        stakeholder: stakeholderDraft,
        ...(welcomeTransaction ? { transaction_summary: welcomeTransaction } : {})
    }
}];

// NODO: stakeholder_Edit
// DESCRIZIONE: Unisce i dati esistenti nel DB con i nuovi dati dal Webhook preservando e allineando solo il chat_id

const input = $input.first().json;

// 1. Recupero i dati
let stakeholder = { ...input.stakeholder };
const newData = input.body || {};
const newUserRef = newData.user || {};
const newBillingArray = newData.fatturazione || [];

// 2. AGGIORNAMENTO USER_REF (Dati Personali)
stakeholder.user_ref = {
    ...stakeholder.user_ref,
    ...newUserRef
};

// Estrazione e allineamento del chat_id (senza toccare user_id)
const currentChatId = stakeholder.user_ref.chat_id || (stakeholder.owner_data_ref ? stakeholder.owner_data_ref.chat_id : null) || (newData.user ? newData.user.chat_id : null);

if (currentChatId) {
    stakeholder.user_ref.chat_id = currentChatId;
}

// 3. AGGIORNAMENTO OWNER_DATA_REF (Fatturazione)
if (newBillingArray.length > 0 && newBillingArray[0]) {
    stakeholder.owner_data_ref = {
        ...stakeholder.owner_data_ref,
        ...newBillingArray[0],
        chat_id: currentChatId || newBillingArray[0].chat_id || (stakeholder.owner_data_ref ? stakeholder.owner_data_ref.chat_id : null)
    };
} else {
    // Sincronizza il chat_id se presente, lasciando intatti gli altri campi di owner_data_ref
    stakeholder.owner_data_ref = stakeholder.owner_data_ref || {};
    if (currentChatId) {
        stakeholder.owner_data_ref.chat_id = stakeholder.owner_data_ref.chat_id || currentChatId;
    }
}

// 4. RICALCOLO OWNER_INSTANCE_ID
let instanceId = stakeholder.owner_instance_id;
if (stakeholder.owner_data_ref.pIva) {
    instanceId = stakeholder.owner_data_ref.pIva.replace('IT', '');
} else if (stakeholder.owner_data_ref.vat_number) {
    instanceId = stakeholder.owner_data_ref.vat_number.replace('IT', '');
} else if (stakeholder.user_ref.codiceFiscale) {
    instanceId = stakeholder.user_ref.codiceFiscale;
}
stakeholder.owner_instance_id = instanceId;

// 5. AGGIORNAMENTO METADATA
stakeholder.metadata = {
    ...stakeholder.metadata,
    last_updated: new Date().toISOString(),
    status: (stakeholder.owner_data_ref.vat_number || stakeholder.owner_data_ref.pIva || stakeholder.owner_data_ref.ragioneSociale) ? "ACTIVE" : "PENDING_BILLING"
};

// 6. LOGICA TAGS
if (stakeholder.metadata.status === "ACTIVE" && !stakeholder.commercial_profile.tags.includes("primary_contact")) {
    stakeholder.commercial_profile.tags.push("primary_contact");
    stakeholder.commercial_profile.tags = stakeholder.commercial_profile.tags.filter(t => t !== "incomplete_profile");
}

return [{
    json: {
        stakeholder: stakeholder
    }
}];

return $input.all().map(item => {
  const uid = item.json.user_id; 

  // --- CODIFICA (Offuscamento Dinamico) ---

  const encoded = uid.split('').map((char, i) => {
    const code = char.charCodeAt(0);

    return String.fromCharCode(code + (i % 3) + 7);
  }).join('');

  const finalID = Buffer.from(encoded).toString('base64');


  return {
    json: {
      ...item,
      user_id_honeypot: finalID
    }
  };
});

const item = $input.first().json;
const ash = item.ash || (item.body ? item.body.ash : null);
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';

if (!ash || !ash.includes('.')) {
    return [{ json: { isValid: false, error: "Ash mancante o malformato" } }];
}

try {
    // 1. Separazione Payload e Firma
    const [encodedPayload, sigReceived] = ash.split('.');
    const decodedPayload = Buffer.from(encodedPayload, 'base64').toString('utf-8');

    // 2. Estrazione parametri (Usiamo | come separatore)
    const parts = decodedPayload.split('|');
    if (parts.length !== 3) {
        return [{ json: { isValid: false, error: "Struttura dati interna ash non valida" } }];
    }

    const [chatId, timestamp, webhookId] = parts;

    // 3. Ricalcolo Firma per verifica
    function generateSignature(str, key) {
        let hash = 0;
        const combined = str + key;
        for (let i = 0; i < combined.length; i++) {
            const char = combined.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; 
        }
        return Math.abs(hash).toString(16);
    }

    const calculatedSig = generateSignature(decodedPayload, SECRET_KEY);

    // 4. Verifica Integrità
    if (sigReceived !== calculatedSig) {
        return [{ json: { isValid: false, error: "Firma non valida: link manomesso" } }];
    }

    return [{
        json: {
            auth_result: {
                isValid: true,
                chatId: chatId,
                timestamp: new Date(parseInt(timestamp)).toISOString(),
                webhookId: webhookId
            }
        }
    }];
} catch (e) {
    return [{ json: { isValid: false, error: "Errore durante la decodifica" } }];
}
